// Startup delay — randomise to avoid predictable bot-like patterns
const delayMinutes = 1;

console.log('Workflow started - waiting ' + delayMinutes + ' minute(s) before processing');

return [{
  json: {
    delayMinutes: delayMinutes,
    message: 'Startup delay before first connection attempt'
  }
}];

// DAILY SAFETY LIMIT — keeps LinkedIn activity within safe human-like range
// LinkedIn flags accounts sending too many requests per day
const minConnections = 8;
const maxConnections = 12;
const dailyLimit = Math.floor(Math.random() * (maxConnections - minConnections + 1)) + minConnections;

// Only process contacts where LinkedIn Connection Sent is blank
const allItems = $input.all();
const unsentItems = allItems.filter(item => 
  !item.json['LinkedIn Connection Sent'] || 
  item.json['LinkedIn Connection Sent'].toString().trim() === ''
);

const limitedItems = unsentItems.slice(0, dailyLimit);

console.log('Total unsent contacts: ' + unsentItems.length);
console.log('Daily limit set to: ' + dailyLimit);
console.log('Processing today: ' + limitedItems.length + ' contacts');

if (limitedItems.length === 0) {
  console.log('No unsent contacts found — workflow complete');
}

return limitedItems.map((item, index) => ({
  json: {
    ...item.json,
    currentIndex: index + 1,
    totalToProcess: limitedItems.length
  }
}));

// FUNCTIONAL AREA DETECTION
// Maps job title keywords to pharma functional areas
// Each area has a tailored AI prompt with specific pain points and benefits

const title = ($json.data?.experience?.[0]?.job_title || $json['Title'] || '').toLowerCase();

const departmentMap = {
  'medical affairs': ['medical affairs', 'msl', 'medical science liaison', 'medical director', 'medical manager'],
  'market access': ['market access', 'payer', 'reimbursement', 'pricing', 'access', 'formulary'],
  'clinical development': ['clinical', 'clinical development', 'clinical operations', 'clinical trial', 'study manager'],
  'regulatory': ['regulatory', 'regulatory affairs', 'compliance', 'regulatory strategy', 'submissions'],
  'commercial': ['commercial', 'marketing', 'sales', 'brand', 'launch', 'product manager'],
  'business development': ['business development', 'bd', 'licensing', 'alliance', 'partnerships'],
  'heor': ['heor', 'health economics', 'outcomes research', 'real world evidence', 'rwe', 'pharmacoeconomics']
};

// Default to clinical development if no match found
let functionalArea = 'clinical development';

for (const [dept, keywords] of Object.entries(departmentMap)) {
  if (keywords.some(keyword => title.includes(keyword))) {
    functionalArea = dept;
    break;
  }
}

console.log('Job title detected: ' + title);
console.log('Mapped to functional area: ' + functionalArea);

return [{
  json: {
    ...$json,
    functionalArea: functionalArea
  }
}];

// MESSAGE QUALITY VALIDATOR
// Ensures every AI-generated message meets LinkedIn character limits
// and follows the required format before sending

const message = $json.text;
const firstName = $json.data.name.split(' ')[0];

const checks = {
  // Must be 100-120 characters (LinkedIn connection note limit is 300 but shorter = higher acceptance)
  length: message.length >= 100 && message.length <= 120,
  // Must reference AI product — proves value proposition
  hasAI: /AI solution|AI application|AI-powered platform|AI platform/i.test(message),
  // Must use first person — sounds human, not automated
  hasFirstPerson: /we have developed|our AI|our platform/i.test(message),
  // Must start with Hi {FirstName}, — personalisation signal
  startsCorrectly: message.startsWith('Hi ' + firstName + ','),
  // Must end with a question — open loop drives replies
  hasCTA: message.trim().endsWith('?')
};

const allPassed = Object.values(checks).every(v => v);

console.log('--- Message Validation Report ---');
console.log('Message: ' + message);
console.log('Length: ' + message.length + ' characters');
console.log('All checks passed: ' + allPassed);
console.log('Individual checks:', checks);

if (!allPassed) {
  const failed = Object.entries(checks)
    .filter(([_, passed]) => !passed)
    .map(([check]) => check);
  console.log('FAILED checks: ' + failed.join(', '));
  console.log('Skipping this contact and moving to next');

  return [{
    json: {
      ...$json,
      messageQuality: 'FAILED',
      failedChecks: failed
    }
  }];
}

console.log('Message approved — proceeding to send');

return [{
  json: {
    ...$json,
    messageQuality: 'PASSED',
    validatedMessage: message
  }
}];

// PRE-SEND HUMAN BEHAVIOUR SIMULATION
// Random 15-35 minute wait before each connection request
// This mimics a human browsing LinkedIn before connecting
// Critical for avoiding LinkedIn automation detection

const minWait = 15;
const maxWait = 35;
const randomWait = Math.floor(Math.random() * (maxWait - minWait + 1)) + minWait;

console.log('Pre-send wait: ' + randomWait + ' minutes');
console.log('About to connect with: ' + $('Process One by One').item.json['First Name'] + ' ' + $('Process One by One').item.json['Last Name']);

// Save all key data to state so it survives the wait node
return [{
  json: {
    ...$json,
    waitMinutes: randomWait,
    savedLinkedInUrl: $('Process One by One').item.json['Person Linkedin Url'],
    savedFirstName: $('Process One by One').item.json['First Name'],
    savedLastName: $('Process One by One').item.json['Last Name'],
    savedMessage: $json.validatedMessage
  }
}];

// SEND RESULT CHECKER
// Determines if the personalised message was sent successfully
// or if we need to fall back to a blank connection request

const sendResult = $('Try Send Connection WITH Message').first();
const sendFailed = sendResult.error || sendResult.json?.error;

if (sendFailed) {
  console.log('Personalised message send FAILED');
  console.log('Reason: ' + (sendResult.error?.message || sendResult.json?.error || 'Unknown error'));
  console.log('Falling back to blank connection request');

  return [{
    json: {
      ...$json,
      messageSentStatus: 'FAILED',
      errorReason: sendResult.error?.message || 'Cannot send note to this profile',
      needsBlankRequest: true
    }
  }];
}

console.log('Personalised connection request sent successfully');

return [{
  json: {
    ...$json,
    messageSentStatus: 'SUCCESS',
    needsBlankRequest: false
  }
}];

// INTER-PERSON DELAY
// Random 10-25 minute wait between each person
// Makes the workflow behave like a human browsing LinkedIn
const minWait = 10;
const maxWait = 25;
const randomWait = Math.floor(Math.random() * (maxWait - minWait + 1)) + minWait;

console.log('Waiting ' + randomWait + ' minutes before processing next contact');

return [{
  json: {
    ...$json,
    nextWaitMinutes: randomWait
  }
}];

// SHORT WAIT FOR SKIPPED CONTACTS
// Skipped contacts still need a pause before moving to next person
const randomWait = Math.floor(Math.random() * 10) + 5;

console.log('Contact skipped — waiting ' + randomWait + ' minutes before next');

return [{
  json: {
    ...$json,
    skipWaitMinutes: randomWait
  }
}];
